# apps/orders/selectors.py from django.db.models import QuerySet, Prefetch
from apps.orders.models import Order, OrderItem
def order_list_for_user( *, user: "User", status: str | None = None, ) -> QuerySet[Order]: """ Get orders for a user with optimized queries.
Args: user: The user to get orders for status: Optional status filter
Returns: QuerySet of orders with prefetched items """ queryset = Order.objects.filter(user=user).prefetch_related( Prefetch( "items", queryset=OrderItem.objects.select_related("product"), ) )
if status: queryset = queryset.filter(status=status)
return queryset.order_by("-created_at")
def order_get_by_id(*, order_id: int, user: "User" = None) -> Order: """ Get single order by ID.
Args: order_id: The order ID user: Optional user for ownership check
Returns: Order instance
Raises: Order.DoesNotExist: If order not found """ queryset = Order.objects.prefetch_related("items__product")
if user: queryset = queryset.filter(user=user)
return queryset.get(id=order_id)

# core/exceptions.py
class ApplicationError(Exception):
    """Base exception for business logic errors."""

    def __init__(self, message: str, extra: dict = None):
        super().__init__(message)
        self.message = message
        self.extra = extra or {}


class NotFoundError(ApplicationError):
    """Resource not found."""
    pass


class ValidationError(ApplicationError):
    """Business validation failed."""
    pass


class PermissionDeniedError(ApplicationError):
    """User lacks permission."""
    pass


# View layer
def custom_exception_handler(exc, context):
    """Handle both DRF and custom exceptions."""
    response = exception_handler(exc, context)

    if response is not None:
        return response

    if isinstance(exc, NotFoundError):
        return Response(
            {"error": exc.message, "extra": exc.extra},
            status=status.HTTP_404_NOT_FOUND,
        )

    if isinstance(exc, ValidationError):
        return Response(
            {"error": exc.message, "extra": exc.extra},
            status=status.HTTP_400_BAD_REQUEST,
        )

    if isinstance(exc, PermissionDeniedError):
        return Response(
            {"error": exc.message},
            status=status.HTTP_403_FORBIDDEN,
        )

    return None

